const raw = $json.body ?? $json.data ?? $json.response ?? $json;
const text = String(raw).trim();
if (!text) return [];

const lines = text.split(/\r?\n/).filter(Boolean);
const headers = lines[0].split(',').map(h => h.trim());
const rows = [];

const dateIdx = headers.findIndex(h => /date|time/i.test(h));
const closeIdx = headers.findIndex(h => /close|price|last/i.test(h));

for (const line of lines.slice(1)) {
  const cols = line.split(',');
  if (dateIdx < 0 || closeIdx < 0) continue;
  const date = (cols[dateIdx] ?? '').trim();
  const close = Number((cols[closeIdx] ?? '').trim());
  if (!date || Number.isNaN(close)) continue;
  rows.push({ date, close });
}

rows.sort((a, b) => new Date(a.date) - new Date(b.date));
return rows.map(r => ({ json: r }));

const raw = $json.body ?? $json.data ?? $json.response ?? $json;
const text = String(raw).trim();
if (!text) return [];

const lines = text.split(/\r?\n/).filter(Boolean);
const headers = lines[0].split(',').map(h => h.trim());
const rows = [];

const dateIdx = headers.findIndex(h => /date|time/i.test(h));
const titleIdx = headers.findIndex(h => /title|headline|news/i.test(h));

for (const line of lines.slice(1)) {
  const cols = line.split(',');
  if (dateIdx < 0 || titleIdx < 0) continue;
  const date = (cols[dateIdx] ?? '').trim();
  const title = (cols[titleIdx] ?? '').trim();
  if (!date || !title) continue;
  rows.push({ date, title });
}

rows.sort((a, b) => new Date(a.date) - new Date(b.date));
return rows.map(r => ({ json: r }));

const grouped = new Map();
for (const item of $input.all()) {
  const date = item.json.date;
  const title = item.json.title;
  if (!date || !title) continue;
  if (!grouped.has(date)) grouped.set(date, []);
  grouped.get(date).push(title);
}

const out = [];
for (const [date, titles] of grouped.entries()) {
  out.push({ json: { date, news_titles: titles, news_joined: titles.join(' | ') } });
}
out.sort((a, b) => new Date(a.json.date) - new Date(b.json.date));
return out;

function rollingMean(arr, idx, w) {
  const from = Math.max(0, idx - w + 1);
  const slice = arr.slice(from, idx + 1);
  const s = slice.reduce((a, b) => a + b, 0);
  return s / slice.length;
}

function rollingStd(arr, idx, w) {
  const from = Math.max(0, idx - w + 1);
  const slice = arr.slice(from, idx + 1);
  const m = slice.reduce((a, b) => a + b, 0) / slice.length;
  const v = slice.reduce((a, b) => a + (b - m) ** 2, 0) / slice.length;
  return Math.sqrt(v);
}

function calcRsi(closes, idx, period = 14) {
  if (idx === 0) return 50;
  const from = Math.max(1, idx - period + 1);
  let gain = 0;
  let loss = 0;
  for (let i = from; i <= idx; i++) {
    const d = closes[i] - closes[i - 1];
    if (d >= 0) gain += d;
    else loss += -d;
  }
  const avgGain = gain / period;
  const avgLoss = loss / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

const all = $input.all();
const market = all
  .filter(x => x.json.close !== undefined)
  .map(x => ({ date: String(x.json.date), close: Number(x.json.close) }))
  .filter(x => x.date && Number.isFinite(x.close))
  .sort((a, b) => new Date(a.date) - new Date(b.date));

const newsMap = new Map();
for (const n of all.filter(x => x.json.news_titles !== undefined)) {
  newsMap.set(String(n.json.date), n.json.news_titles || []);
}

const closes = market.map(x => x.close);
const out = market.map((row, i) => {
  const sma20 = rollingMean(closes, i, 20);
  const std20 = rollingStd(closes, i, 20);
  const bbUpper = sma20 + 2 * std20;
  const bbLower = sma20 - 2 * std20;
  const sma50 = rollingMean(closes, i, 50);
  const rsi = calcRsi(closes, i, 14);
  const newsTitles = newsMap.get(row.date) || [];

  return {
    json: {
      date: row.date,
      close: row.close,
      rsi,
      sma_50: sma50,
      bb_upper: bbUpper,
      bb_lower: bbLower,
      news_titles: newsTitles,
      news_joined: newsTitles.join(' | '),
    },
  };
});

return out;

const symbol = $env.SYMBOL || 'BTCUSDT';
const timeframe = $env.TIMEFRAME || '1d';
const model = $env.HF_MODEL || 'mistralai/Mistral-7B-Instruct-v0.3';

return $input.all().map(item => {
  const row = item.json;
  const prompt = [
    'You are a cautious financial analyst assistant.',
    'Return strict JSON: fear_greed (0..100), sentiment_label, sentiment_score (-1..1), analysis_short.',
    `Symbol: ${symbol}`,
    `Timeframe: ${timeframe}`,
    `RSI: ${Number(row.rsi).toFixed(2)}`,
    `SMA_50: ${Number(row.sma_50).toFixed(4)}`,
    `Price: ${Number(row.close).toFixed(4)}`,
    `Recent News: ${row.news_joined || 'none'}`,
  ].join('\n');

  return {
    json: {
      ...row,
      symbol,
      timeframe,
      hf_payload: {
        model,
        messages: [
          { role: 'system', content: 'You are a cautious trading assistant. Educational analysis only.' },
          { role: 'user', content: prompt },
        ],
        temperature: 0.1,
        max_tokens: 220,
      },
    },
  };
});

function parseMaybeJson(text) {
  try { return JSON.parse(text); } catch {}
  const m = String(text || '').match(/\{[\s\S]*\}/);
  if (!m) return null;
  try { return JSON.parse(m[0]); } catch { return null; }
}

function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }

const items = $input.all();
const rows = [];

for (const item of items) {
  const row = { ...item.json };
  let llm = null;

  if (row.choices && Array.isArray(row.choices) && row.choices.length > 0) {
    llm = parseMaybeJson(row.choices[0]?.message?.content || '');
  } else if (row.data?.choices) {
    llm = parseMaybeJson(row.data.choices[0]?.message?.content || '');
  }

  const sentimentScore = Number(llm?.sentiment_score ?? 0);
  const fearGreed = Number(llm?.fear_greed ?? (50 + sentimentScore * 35));

  const rsi = Number(row.rsi);
  const close = Number(row.close);
  const bbUpper = Number(row.bb_upper);
  const bbLower = Number(row.bb_lower);

  const signalA = rsi >= 70 ? 'SELL' : rsi <= 30 ? 'BUY' : 'HOLD';

  let signalB = 'HOLD';
  if (fearGreed >= 80 && rsi >= 70 && close >= bbUpper) signalB = 'SELL';
  else if (fearGreed <= 20 && rsi <= 30 && close <= bbLower) signalB = 'BUY';
  else if (fearGreed >= 60 && sentimentScore >= 0.2 && rsi >= 25) signalB = 'SELL';
  else if (fearGreed <= 40 && sentimentScore <= -0.2 && rsi <= 55) signalB = 'BUY';
  else if (sentimentScore >= 0.25 && rsi <= 45) signalB = 'BUY';
  else if (sentimentScore <= -0.25 && rsi >= 55) signalB = 'SELL';

  rows.push({
    date: row.date,
    close,
    rsi,
    bb_lower: bbLower,
    bb_upper: bbUpper,
    fear_greed: clamp(fearGreed, 0, 100),
    sentiment_score: clamp(sentimentScore, -1, 1),
    signal_a: signalA,
    signal_b: signalB,
  });
}

rows.sort((a, b) => new Date(a.date) - new Date(b.date));

let posA = 0;
let posB = 0;
let prevClose = null;
let cumA = 0;
let cumB = 0;

const out = [];
for (const r of rows) {
  if (r.signal_a === 'BUY') posA = 1;
  if (r.signal_a === 'SELL') posA = -1;
  if (r.signal_b === 'BUY') posB = 1;
  if (r.signal_b === 'SELL') posB = -1;

  const ret = prevClose ? (r.close - prevClose) / prevClose : 0;
  const dailyA = (prevClose ? posA : 0) * ret;
  const dailyB = (prevClose ? posB : 0) * ret;
  cumA = (1 + cumA) * (1 + dailyA) - 1;
  cumB = (1 + cumB) * (1 + dailyB) - 1;

  out.push({
    json: {
      ...r,
      pos_a: posA,
      pos_b: posB,
      daily_a: dailyA,
      daily_b: dailyB,
      cum_a: cumA,
      cum_b: cumB,
    },
  });

  prevClose = r.close;
}

return out;

const rows = $input.all().map(i => i.json);
if (!rows.length) {
  return [{ json: { csv: '', rows: 0 } }];
}

const headers = [
  'date','close','rsi','bb_lower','bb_upper','fear_greed','sentiment_score',
  'signal_a','signal_b','pos_a','pos_b','daily_a','daily_b','cum_a','cum_b'
];

const escapeCsv = (v) => {
  const s = String(v ?? '');
  if (/[",\n]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
  return s;
};

const lines = [headers.join(',')];
for (const r of rows) {
  lines.push(headers.map(h => escapeCsv(r[h])).join(','));
}

const csv = lines.join('\n');
return [{
  json: {
    rows: rows.length,
    latest_signal_a: rows[rows.length - 1].signal_a,
    latest_signal_b: rows[rows.length - 1].signal_b,
    csv,
  },
}];
